"use client";

import * as React from "react";
import {
  Container,
  Badge,
  Button,
  PersonCell,
  Statistic,
  Delta,
  Meter,
  ScheduleGrid,
  Alert,
  AlertTitle,
  AlertDescription,
  Select,
  Tag,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  AvatarGroup,
  Avatar,
  AvatarFallback,
  Separator,
  type ScheduleCell,
  type ScheduleCellTone,
} from "@gunjo/ui";
import {
  EMPLOYEES,
  DEPARTMENTS,
  PERIOD,
  WEEKDAY_LABELS,
  DAY_KIND_META,
  OVERTIME_WARN,
  OVERTIME_LIMIT,
  DAYS_IN_MONTH,
  overtimeTone,
  summarize,
  APPROVAL_META,
  type Employee,
  type DayKind,
} from "./data";
import { EmployeeDetail } from "./EmployeeDetail";

// 日区分 → ScheduleGrid のセル tone
const KIND_TONE: Record<DayKind, ScheduleCellTone> = {
  work: "default",
  holiday: "muted",
  "paid-leave": "info",
  absent: "destructive",
  late: "warning",
  "early-leave": "warning",
  "field-direct": "primary",
  "half-leave": "info",
};

function overtimeBadge(ot: number) {
  const tone = overtimeTone(ot);
  if (tone === "over")
    return <Badge variant="destructive">残業 {ot}h・80h超</Badge>;
  if (tone === "warn") return <Badge variant="warning">残業 {ot}h・45h超</Badge>;
  return <Badge variant="outline">残業 {ot}h</Badge>;
}

export default function AttendanceManagementPage() {
  const [dept, setDept] = React.useState<string>(DEPARTMENTS[0]);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);

  const team = React.useMemo(
    () => EMPLOYEES.filter((e) => e.dept === dept),
    [dept]
  );
  const allSummary = summarize(EMPLOYEES);
  const selected = EMPLOYEES.find((e) => e.id === selectedId) ?? null;

  // 36協定の超過者（全社）
  const atRisk = EMPLOYEES.filter((e) => overtimeTone(e.overtime) !== "ok");
  const overLimit = atRisk.filter((e) => overtimeTone(e.overtime) === "over");

  // ---- ScheduleGrid 用の行・列・セル ----
  const columns = React.useMemo(
    () =>
      Array.from({ length: DAYS_IN_MONTH }, (_, i) => {
        const day = i + 1;
        const wd = ((day - 1 + 1) % 7);
        return {
          id: `d${day}`,
          label: (
            <span className="flex flex-col items-center leading-tight">
              <span className="tabular-nums">{day}</span>
              <span
                className={
                  wd === 0
                    ? "text-destructive"
                    : wd === 6
                      ? "text-info"
                      : "text-muted-foreground"
                }
              >
                {WEEKDAY_LABELS[wd]}
              </span>
            </span>
          ),
          ariaLabel: `6月${day}日 ${WEEKDAY_LABELS[wd]}曜日`,
        };
      }),
    []
  );

  const rows = React.useMemo(
    () =>
      team.map((e) => ({
        id: e.id,
        label: (
          <button
            type="button"
            onClick={() => setSelectedId(e.id)}
            className="flex w-full flex-col items-start gap-0.5 rounded text-left focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
          >
            <span className="truncate text-xs font-medium text-foreground">
              {e.name}
            </span>
            <span className="truncate text-[10px] text-muted-foreground">
              {e.role}
            </span>
          </button>
        ),
        ariaLabel: e.name,
      })),
    [team]
  );

  const cells = React.useMemo<ScheduleCell[]>(() => {
    const out: ScheduleCell[] = [];
    for (const e of team) {
      for (const d of e.days) {
        const meta = DAY_KIND_META[d.kind];
        const heavy = (d.overtime ?? 0) >= 4;
        out.push({
          rowId: e.id,
          colId: `d${d.day}`,
          tone: heavy && d.kind === "work" ? "warning" : KIND_TONE[d.kind],
          onSelect: () => setSelectedId(e.id),
          description:
            d.kind === "work"
              ? `${d.in}〜${d.out}、実働${d.actual}時間${d.overtime ? `、残業${d.overtime}時間` : ""}${d.amendment ? "、打刻修正あり" : ""}`
              : meta.label,
          content: (
            <span className="flex flex-col items-center justify-center gap-0.5 leading-none">
              {d.kind === "work" ? (
                <>
                  <span className="text-[10px] tabular-nums text-foreground">
                    {d.in}
                  </span>
                  <span className="text-[10px] tabular-nums text-muted-foreground">
                    {d.out}
                  </span>
                  {d.overtime ? (
                    <span
                      className={
                        heavy
                          ? "text-[9px] font-semibold tabular-nums text-warning"
                          : "text-[9px] tabular-nums text-muted-foreground"
                      }
                    >
                      +{d.overtime}
                    </span>
                  ) : null}
                </>
              ) : (
                <span className="text-[11px] font-medium">{meta.short}</span>
              )}
              {d.amendment ? (
                <span
                  aria-hidden
                  className="mt-0.5 h-1 w-1 rounded-full bg-warning"
                />
              ) : null}
            </span>
          ),
        });
      }
    }
    return out;
  }, [team]);

  const teamSummary = summarize(team);

  return (
    <Container size="2xl" className="py-6">
      {/* ===== ヘッダー ===== */}
      <div className="mb-6 flex flex-wrap items-start justify-between gap-4">
        <div>
          <p className="text-xs font-medium text-muted-foreground">勤怠管理・工数管理</p>
          <h1 className="text-2xl font-bold tracking-tight">月次勤怠 — {PERIOD}</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            労務担当：小林 香織 ・ 締め日 6/30 ・ 確定期限 7/5
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm">
            CSV出力
          </Button>
          <Button size="sm">一括承認</Button>
        </div>
      </div>

      {/* ===== 36協定アラート ===== */}
      {atRisk.length > 0 ? (
        <Alert variant="warning" className="mb-5">
          <AlertTitle as="h2">
            36協定アラート：残業 45時間超 {atRisk.length}名（うち 80時間超{" "}
            {overLimit.length}名）
          </AlertTitle>
          <AlertDescription>
            <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
              {atRisk.map((e) => (
                <button
                  key={e.id}
                  type="button"
                  onClick={() => setSelectedId(e.id)}
                  className="rounded focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                >
                  <Badge variant={overtimeTone(e.overtime) === "over" ? "destructive" : "warning"}>
                    {e.name}・{e.overtime}h
                  </Badge>
                </button>
              ))}
            </div>
          </AlertDescription>
        </Alert>
      ) : null}

      {/* ===== サマリ指標 ===== */}
      <div className="mb-6 grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
        <Statistic label="対象社員" value={`${allSummary.headcount}名`} hint={`${DEPARTMENTS.length}部署`} />
        <Statistic
          label="平均残業時間"
          value={`${allSummary.avgOvertime}h`}
          trend={allSummary.avgOvertime > OVERTIME_WARN ? "up" : "flat"}
          tone={allSummary.avgOvertime > OVERTIME_WARN ? "negative" : "neutral"}
          hint="1人あたり/月"
        />
        <Statistic
          label="36協定アラート"
          value={`${allSummary.warnCount}名`}
          trend={allSummary.warnCount > 0 ? "up" : "flat"}
          tone={allSummary.warnCount > 0 ? "negative" : "positive"}
          hint={`80h超 ${allSummary.overCount}名`}
        />
        <Statistic label="有休消化率" value={`${allSummary.paidLeaveRate}%`} hint="今年度" />
        <Statistic
          label="未承認"
          value={`${allSummary.unapproved}件`}
          trend={allSummary.unapproved > 0 ? "up" : "flat"}
          tone={allSummary.unapproved > 0 ? "negative" : "positive"}
          hint="労務確定前"
        />
      </div>

      {/* ===== 月次マトリクス（社員 × 日付） ===== */}
      <section className="mb-8 rounded-xl border border-border bg-card p-4">
        <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <h2 className="text-base font-semibold">月次勤怠マトリクス</h2>
            <Badge variant="secondary">{team.length}名</Badge>
          </div>
          <div className="flex items-center gap-3">
            <Select
              aria-label="部署を選択"
              value={dept}
              onChange={(e) => setDept(e.target.value)}
              className="w-48"
            >
              {DEPARTMENTS.map((d) => (
                <option key={d} value={d}>
                  {d}
                </option>
              ))}
            </Select>
          </div>
        </div>

        {/* 凡例 */}
        <div className="mb-3 flex flex-wrap items-center gap-2 text-xs">
          {(
            [
              ["paid-leave", "有"],
              ["absent", "欠"],
              ["late", "遅"],
              ["early-leave", "早"],
              ["field-direct", "直"],
              ["half-leave", "半"],
              ["holiday", "休"],
            ] as [DayKind, string][]
          ).map(([k, short]) => (
            <Tag key={k} size="sm" variant="outline">
              <span className="font-semibold">{short}</span>
              <span className="text-muted-foreground">{DAY_KIND_META[k].label}</span>
            </Tag>
          ))}
          <span className="ml-1 inline-flex items-center gap-1 text-muted-foreground">
            <span className="h-1.5 w-1.5 rounded-full bg-warning" />
            打刻修正あり
          </span>
        </div>

        <ScheduleGrid
          label={`${dept} の${PERIOD}勤怠マトリクス`}
          rows={rows}
          columns={columns}
          cells={cells}
          cornerLabel="社員 / 日"
          minColumnWidth={56}
          rowHeaderWidth={132}
        />
        <p className="mt-2 text-xs text-muted-foreground">
          各セルの上段＝出勤打刻、下段＝退勤打刻、+n＝残業時間。セルを選択すると本人の詳細を開きます。
        </p>
      </section>

      {/* ===== 社員一覧（勤怠ステータス） ===== */}
      <section className="rounded-xl border border-border bg-card p-4">
        <h2 className="mb-1 text-base font-semibold">社員別 勤怠ステータス（全社）</h2>
        <p className="mb-4 text-sm text-muted-foreground">
          行を選択すると、本人の日次打刻・残業推移・承認状況を確認できます。
        </p>
        <ul className="flex flex-col divide-y divide-border">
          {EMPLOYEES.map((e) => {
            const approval = APPROVAL_META[e.approval];
            return (
              <li key={e.id}>
                <button
                  type="button"
                  onClick={() => setSelectedId(e.id)}
                  className="flex w-full items-center gap-3 py-3 text-left transition-colors hover:bg-muted/40 focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                >
                  <div className="min-w-0 flex-1">
                    <PersonCell
                      name={e.name}
                      secondary={`${e.dept} ・ ${e.role}`}
                      tertiary={`${e.employment} ・ 上長: ${e.managerName}`}
                      avatar={{ fallback: e.name.slice(0, 1) }}
                      avatarClassName={e.avatarColor}
                    />
                  </div>
                  <div className="hidden shrink-0 flex-col items-end gap-1 sm:flex">
                    <span className="text-xs text-muted-foreground">有休残</span>
                    <span className="text-sm font-medium tabular-nums">
                      {e.paidLeaveRemaining}日
                    </span>
                  </div>
                  <div className="flex shrink-0 flex-col items-end gap-1.5">
                    {overtimeBadge(e.overtime)}
                    <Badge variant={approval.badge}>{approval.label}</Badge>
                  </div>
                </button>
              </li>
            );
          })}
        </ul>

        <Separator className="my-4" />
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <span>承認待ちの担当者：</span>
            <AvatarGroup max={4}>
              {EMPLOYEES.filter(
                (e) => e.approval === "submitted" || e.approval === "approved"
              ).map((e) => (
                <Avatar key={e.id} className="h-7 w-7">
                  <AvatarFallback className={`text-xs ${e.avatarColor}`}>
                    {e.name.slice(0, 1)}
                  </AvatarFallback>
                </Avatar>
              ))}
            </AvatarGroup>
          </div>
          <Delta
            value={-allSummary.unapproved}
            format={(v) => `${Math.abs(v)}件 未確定`}
            labels={{ negative: "労務確定が必要" }}
            tones={{ negative: "warning" }}
            hideArrow
          />
        </div>
      </section>

      {/* ===== 社員詳細ドリルイン ===== */}
      <Sheet
        open={selected != null}
        onOpenChange={(o) => !o && setSelectedId(null)}
      >
        <SheetContent
          side="right"
          className="w-full overflow-y-auto sm:max-w-xl"
        >
          {selected ? (
            <>
              <SheetHeader>
                <SheetTitle>{selected.name} の勤怠詳細</SheetTitle>
                <SheetDescription>
                  {PERIOD} ・ {selected.dept}
                </SheetDescription>
              </SheetHeader>
              <div className="mt-4">
                <EmployeeDetail employee={selected} />
              </div>
            </>
          ) : null}
        </SheetContent>
      </Sheet>
    </Container>
  );
}

// 勤怠管理 / 工数管理 — 2026年6月度サンプルデータ
// 在籍する架空のHR/労務チームと各社員の月次打刻・残業・休暇・承認状態。

export const PERIOD = "2026年6月度";
export const PERIOD_START = "2026-06-01";
export const DAYS_IN_MONTH = 30;
export const OVERTIME_WARN = 45; // 36協定 月45時間
export const OVERTIME_LIMIT = 80; // 特別条項 月80時間

export type DayKind =
  | "work" // 出勤（打刻あり）
  | "holiday" // 休日（所定休日）
  | "paid-leave" // 有休
  | "absent" // 欠勤
  | "late" // 遅刻
  | "early-leave" // 早退
  | "field-direct" // 直行直帰
  | "half-leave"; // 半休

export interface DayRecord {
  /** 1–30 */
  day: number;
  /** 曜日 0=日 */
  weekday: number;
  kind: DayKind;
  /** 出勤打刻 HH:mm */
  in?: string;
  /** 退勤打刻 HH:mm */
  out?: string;
  /** 実働(時間) */
  actual?: number;
  /** 残業(時間) */
  overtime?: number;
  /** 打刻修正の申請があるか */
  amendment?: { reason: string; status: "pending" | "approved" };
  note?: string;
}

export type ApprovalState =
  | "not-submitted" // 未提出（本人）
  | "submitted" // 提出済（一次承認待ち）
  | "approved" // 上長承認済（労務確定待ち）
  | "finalized" // 労務確定
  | "sent-back"; // 差戻し

export interface Employee {
  id: string;
  name: string;
  nameKana: string;
  dept: string;
  role: string;
  employment: "正社員" | "契約社員" | "時短勤務" | "フレックス";
  avatarColor: string; // deterministic bg for avatar fallback
  managerId?: string;
  managerName: string;
  overtime: number; // 月間残業合計
  actualTotal: number; // 月間実働合計
  paidLeaveRemaining: number; // 有休残日数
  paidLeaveTaken: number; // 当月取得日数
  paidLeaveGranted: number; // 付与日数（消化率算出用）
  paidLeavePending?: { date: string; days: number }; // 申請中の有休
  approval: ApprovalState;
  approvedBy?: string;
  approvedAt?: string;
  finalizedAt?: string;
  sentBackReason?: string;
  days: DayRecord[];
}

const DEPTS = ["プロダクト開発部", "カスタマーサクセス部", "コーポレート本部"] as const;

// 6月のカレンダー: 2026-06-01 は月曜。土日を休日に。
function weekdayOf(day: number): number {
  // 2026-06-01 = Monday(1)
  return ((day - 1 + 1) % 7); // day1 -> 1(Mon)
}

function isWeekend(day: number): boolean {
  const w = weekdayOf(day);
  return w === 0 || w === 6;
}

// 1日分の標準的な勤務を生成
function workDay(
  day: number,
  opts: Partial<DayRecord> & { in: string; out: string }
): DayRecord {
  const [ih, im] = opts.in.split(":").map(Number);
  const [oh, om] = opts.out.split(":").map(Number);
  const gross = oh + om / 60 - (ih + im / 60);
  const actual = Math.max(0, Math.round((gross - 1) * 10) / 10); // 休憩1h
  const overtime = Math.max(0, Math.round((actual - 8) * 10) / 10);
  return {
    day,
    weekday: weekdayOf(day),
    kind: opts.kind ?? "work",
    in: opts.in,
    out: opts.out,
    actual,
    overtime,
    amendment: opts.amendment,
    note: opts.note,
  };
}

// 各社員の月次日次レコードを、残業傾向(intensity)に応じて生成する。
function buildMonth(
  seed: number,
  intensity: "low" | "mid" | "high" | "over",
  overrides: Record<number, Partial<DayRecord> & { kind: DayKind }> = {}
): DayRecord[] {
  const out: DayRecord[] = [];
  for (let day = 1; day <= DAYS_IN_MONTH; day++) {
    if (overrides[day]) {
      const o = overrides[day];
      if (o.kind === "work" || o.kind === "late" || o.kind === "early-leave" || o.kind === "field-direct") {
        out.push(workDay(day, { in: o.in ?? "09:00", out: o.out ?? "18:00", ...o }));
      } else {
        out.push({ day, weekday: weekdayOf(day), kind: o.kind, note: o.note, amendment: o.amendment });
      }
      continue;
    }
    if (isWeekend(day)) {
      out.push({ day, weekday: weekdayOf(day), kind: "holiday" });
      continue;
    }
    // 平日の残業傾向。seedで微妙に揺らす。
    const wobble = ((day * (seed + 3)) % 5) - 2; // -2..2
    let endHour: number;
    switch (intensity) {
      case "low":
        endHour = 18 + (wobble > 1 ? 0.5 : 0);
        break;
      case "mid":
        endHour = 19 + (wobble * 0.25);
        break;
      case "high":
        endHour = 20.5 + (wobble * 0.25);
        break;
      case "over":
        endHour = 21.5 + (wobble * 0.3);
        break;
    }
    const oh = Math.floor(endHour);
    const om = Math.round((endHour - oh) * 60);
    const inH = intensity === "over" && day % 7 === 3 ? "09:30" : "09:00";
    out.push(
      workDay(day, {
        in: inH,
        out: `${String(oh).padStart(2, "0")}:${String(om).padStart(2, "0")}`,
      })
    );
  }
  return out;
}

function sum(days: DayRecord[], key: "actual" | "overtime"): number {
  return Math.round(days.reduce((a, d) => a + (d[key] ?? 0), 0) * 10) / 10;
}

function makeEmployee(
  base: Omit<
    Employee,
    "overtime" | "actualTotal" | "days"
  > & { days: DayRecord[] }
): Employee {
  return {
    ...base,
    overtime: sum(base.days, "overtime"),
    actualTotal: sum(base.days, "actual"),
  };
}

