// ---- 集計ヘルパー ----

export function overtimeTone(ot: number): "ok" | "warn" | "over" {
  if (ot >= OVERTIME_LIMIT) return "over";
  if (ot >= OVERTIME_WARN) return "warn";
  return "ok";
}

export interface Summary {
  headcount: number;
  avgOvertime: number;
  warnCount: number; // 45h超
  overCount: number; // 80h超
  paidLeaveRate: number; // 消化率 %
  unapproved: number; // 未承認（finalized以外）
}

export function summarize(list: Employee[]): Summary {
  const headcount = list.length;
  const avgOvertime =
    Math.round((list.reduce((a, e) => a + e.overtime, 0) / headcount) * 10) / 10;
  const warnCount = list.filter((e) => overtimeTone(e.overtime) !== "ok").length;
  const overCount = list.filter((e) => overtimeTone(e.overtime) === "over").length;
  const grantedTotal = list.reduce((a, e) => a + e.paidLeaveGranted, 0);
  const takenTotal = list.reduce(
    (a, e) => a + (e.paidLeaveGranted - e.paidLeaveRemaining),
    0
  );
  const paidLeaveRate = Math.round((takenTotal / grantedTotal) * 100);
  const unapproved = list.filter((e) => e.approval !== "finalized").length;
  return { headcount, avgOvertime, warnCount, overCount, paidLeaveRate, unapproved };
}

