];

function dailyOvertimeSeries(emp: Employee): number[] {
  // 平日のみの残業推移
  return emp.days.filter((d) => d.kind !== "holiday").map((d) => d.overtime ?? 0);
}

function kindTagVariant(
  kind: Employee["days"][number]["kind"]
): "default" | "secondary" | "outline" | "destructive" {
  switch (kind) {
    case "absent":
      return "destructive";
    case "paid-leave":
    case "half-leave":
      return "secondary";
    case "late":
    case "early-leave":
      return "outline";
    default:
      return "default";
  }
}

